```hcl
# KMS キーポリシーをアカウントルートに制限して、公開 ("*") プリンシパルを避ける
data "aws_caller_identity" "current" {}

resource "aws_kms_key" "<example_resource_name>" {
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = { AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root" } # 重要: 公開アクセスを削除するためにアカウントルートに制限
        Action    = "kms:*"
        Resource  = "*"
      }
    ]
  })
}
```
